const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');

const app = express();

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 15 * 60 * 1000,
    sameSite: 'strict'
  }
}));

const mfaStore = new Map();

const MFA_CODE_LENGTH = 6;
const MFA_CODE_EXPIRY = 5 * 60 * 1000;
const MAX_VERIFICATION_ATTEMPTS = 3;
const LOCKOUT_DURATION = 15 * 60 * 1000;
const RATE_LIMIT_WINDOW = 15 * 60 * 1000;
const MAX_SMS_REQUESTS = 3;

const smsRateLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  max: MAX_SMS_REQUESTS,
  message: 'Too many SMS requests. Please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => {
    return req.session.userId || req.ip;
  }
});

const verifyRateLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  max: 10,
  message: 'Too many verification attempts. Please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => {
    return req.session.userId || req.ip;
  }
});

function generateSecureCode() {
  const buffer = crypto.randomBytes(4);
  const number = buffer.readUInt32BE(0);
  const code = (number % 1000000).toString().padStart(MFA_CODE_LENGTH, '0');
  return code;
}

function hashCode(code, salt) {
  return crypto.pbkdf2Sync(code, salt, 10000, 64, 'sha512').toString('hex');
}

async function sendSMS(phoneNumber, code) {
  const accountSid = process.env.TWILIO_ACCOUNT_SID;
  const authToken = process.env.TWILIO_AUTH_TOKEN;
  const fromNumber = process.env.TWILIO_PHONE_NUMBER;

  if (!accountSid || !authToken || !fromNumber) {
    console.error('Twilio credentials not configured');
    throw new Error('SMS service not configured');
  }

  const twilio = require('twilio');
  const client = twilio(accountSid, authToken);

  try {
    await client.messages.create({
      body: `Your verification code is: ${code}. This code will expire in 5 minutes. Do not share this code with anyone.`,
      from: fromNumber,
      to: phoneNumber
    });
    return true;
  } catch (error) {
    console.error('SMS sending failed:', error.message);
    throw new Error('Failed to send SMS');
  }
}

function validatePhoneNumber(phoneNumber) {
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return phoneRegex.test(phoneNumber);
}

function isAccountLocked(userId) {
  const mfaData = mfaStore.get(userId);
  if (!mfaData) return false;
  
  if (mfaData.lockedUntil && Date.now() < mfaData.lockedUntil) {
    return true;
  }
  
  if (mfaData.lockedUntil && Date.now() >= mfaData.lockedUntil) {
    mfaData.lockedUntil = null;
    mfaData.attempts = 0;
  }
  
  return false;
}

